import { createHash } from "node:crypto";
import type { IncomingMessage, Server } from "node:http";
import type { Socket } from "node:net";

import {
  AUTOMATON_EVENT_TYPES,
  SPAWN_EVENT_TYPES,
  type RealtimeEvent
} from "@ic-automaton/shared";

const WEBSOCKET_GUID = "258EAFA5-E914-47DA-95CA-C5AB0DC85B11";

interface RealtimeClient {
  canisterId?: string;
  socket: Socket;
}

export interface RealtimeSnapshot {
  websocketPath: string;
  clientCount: number;
  supportedEventTypes: string[];
}

function encodeTextFrame(payload: string) {
  const message = Buffer.from(payload);

  if (message.length < 126) {
    return Buffer.concat([Buffer.from([0x81, message.length]), message]);
  }

  if (message.length < 65_536) {
    const header = Buffer.alloc(4);
    header[0] = 0x81;
    header[1] = 126;
    header.writeUInt16BE(message.length, 2);
    return Buffer.concat([header, message]);
  }

  const header = Buffer.alloc(10);
  header[0] = 0x81;
  header[1] = 127;
  header.writeBigUInt64BE(BigInt(message.length), 2);
  return Buffer.concat([header, message]);
}

function extractEventCanisterIds(event: RealtimeEvent) {
  switch (event.type) {
    case "spawn":
      return [event.automaton.canisterId];
    case "update":
    case "action":
    case "monologue":
    case "offline":
      return [event.canisterId];
    case "message":
      return [event.fromCanisterId, event.toCanisterId];
    default:
      return [];
  }
}

export function shouldDeliverEvent(canisterId: string | undefined, event: RealtimeEvent) {
  if (!canisterId) {
    return true;
  }

  return extractEventCanisterIds(event).includes(canisterId);
}

export class RealtimeHub {
  private readonly clients = new Set<RealtimeClient>();
  private server?: Server;
  private readonly handleUpgradeBound: (
    request: IncomingMessage,
    socket: Socket,
    head: Buffer
  ) => void;

  constructor(readonly websocketPath = "/ws/events") {
    this.handleUpgradeBound = this.handleUpgrade.bind(this);
  }

  attach(server: Server) {
    if (this.server === server) {
      return;
    }

    if (this.server) {
      this.server.off("upgrade", this.handleUpgradeBound);
    }

    this.server = server;
    this.server.on("upgrade", this.handleUpgradeBound);
  }

  async close() {
    if (this.server) {
      this.server.off("upgrade", this.handleUpgradeBound);
      this.server = undefined;
    }

    for (const client of this.clients) {
      client.socket.end();
      client.socket.destroy();
    }

    this.clients.clear();
  }

  broadcast(event: RealtimeEvent) {
    const frame = encodeTextFrame(JSON.stringify(event));

    for (const client of this.clients) {
      if (client.socket.destroyed) {
        this.clients.delete(client);
        continue;
      }

      if (!shouldDeliverEvent(client.canisterId, event)) {
        continue;
      }

      client.socket.write(frame);
    }
  }

  getSnapshot(): RealtimeSnapshot {
    return {
      websocketPath: this.websocketPath,
      clientCount: this.clients.size,
      supportedEventTypes: [
        ...AUTOMATON_EVENT_TYPES,
        ...SPAWN_EVENT_TYPES
      ]
    };
  }

  private handleUpgrade(request: IncomingMessage, socket: Socket, head: Buffer) {
    const requestUrl = new URL(request.url ?? this.websocketPath, "http://127.0.0.1");
    if (requestUrl.pathname !== this.websocketPath) {
      return;
    }

    const key = request.headers["sec-websocket-key"];
    const upgrade = request.headers.upgrade;

    if (typeof key !== "string" || upgrade?.toLowerCase() !== "websocket") {
      socket.write("HTTP/1.1 400 Bad Request\r\n\r\n");
      socket.destroy();
      return;
    }

    const accept = createHash("sha1")
      .update(`${key}${WEBSOCKET_GUID}`)
      .digest("base64");

    socket.write(
      [
        "HTTP/1.1 101 Switching Protocols",
        "Upgrade: websocket",
        "Connection: Upgrade",
        `Sec-WebSocket-Accept: ${accept}`,
        "\r\n"
      ].join("\r\n")
    );

    if (head.length > 0) {
      socket.unshift(head);
    }

    socket.setNoDelay(true);

    const client: RealtimeClient = {
      socket,
      canisterId: requestUrl.searchParams.get("canisterId") ?? undefined
    };

    this.clients.add(client);

    const cleanup = () => {
      this.clients.delete(client);
    };

    socket.on("close", cleanup);
    socket.on("end", cleanup);
    socket.on("error", cleanup);
  }
}

use crate::controllers::complete_controller_handoff;
use crate::init::initialize_automaton;
use crate::state::{record_session_audit, write_state};
use crate::types::{
    amount_to_string, parse_amount, FactoryError, PaymentStatus, SessionAuditActor,
    SpawnExecutionReceipt, SpawnSessionState, SpawnedAutomatonRecord,
};

pub fn execute_spawn(session_id: &str, now_ms: u64) -> Result<SpawnExecutionReceipt, FactoryError> {
    write_state(|state| {
        let (payment_status, session_state, expires_at) =
            {
                let session = state.sessions.get(session_id).ok_or_else(|| {
                    FactoryError::SessionNotFound {
                        session_id: session_id.to_string(),
                    }
                })?;
                (
                    session.payment_status.clone(),
                    session.state.clone(),
                    session.expires_at,
                )
            };

        if now_ms > expires_at {
            return Err(FactoryError::SessionExpired {
                session_id: session_id.to_string(),
                expires_at,
            });
        }

        if payment_status != PaymentStatus::Paid {
            return Err(FactoryError::PaymentNotSettled {
                session_id: session_id.to_string(),
                status: payment_status,
            });
        }

        match session_state {
            SpawnSessionState::PaymentDetected | SpawnSessionState::Failed => {}
            SpawnSessionState::Complete => {
                let session = state.sessions.get(session_id).expect("session exists");
                return Ok(SpawnExecutionReceipt {
                    session_id: session.session_id.clone(),
                    automaton_canister_id: session
                        .automaton_canister_id
                        .clone()
                        .expect("completed session has canister id"),
                    automaton_evm_address: session
                        .automaton_evm_address
                        .clone()
                        .expect("completed session has evm address"),
                    funded_amount: session.net_forward_amount.clone(),
                    controller: format!(
                        "controller:{}",
                        session
                            .automaton_canister_id
                            .clone()
                            .expect("completed session has canister id")
                    ),
                    completed_at: session.updated_at,
                });
            }
            state => {
                return Err(FactoryError::SessionNotReadyForSpawn {
                    session_id: session_id.to_string(),
                    state,
                });
            }
        }

        let previous_state = {
            let session = state.sessions.get(session_id).expect("session exists");
            session.state.clone()
        };
        {
            let session = state.sessions.get_mut(session_id).expect("session exists");
            session.state = SpawnSessionState::Spawning;
            session.retryable = false;
            session.refundable = false;
            session.updated_at = now_ms;
        }
        record_session_audit(
            state,
            session_id,
            Some(previous_state),
            SpawnSessionState::Spawning,
            SessionAuditActor::System,
            now_ms,
            "spawn execution started",
        );

        state.next_automaton_nonce += 1;

        let version_commit = state.version_commit.clone();
        let mut runtime = {
            let session = state.sessions.get(session_id).expect("session exists");
            let canister_id = session
                .automaton_canister_id
                .clone()
                .unwrap_or_else(|| format!("automaton-{:04}", state.next_automaton_nonce));
            let evm_address = session
                .automaton_evm_address
                .clone()
                .unwrap_or_else(|| format!("0x{:040x}", state.next_automaton_nonce));
            initialize_automaton(session, canister_id, evm_address, now_ms)
        };

        {
            let session = state.sessions.get_mut(session_id).expect("session exists");
            session.automaton_canister_id = Some(runtime.canister_id.clone());
            session.automaton_evm_address = Some(runtime.evm_address.clone());
            session.state = SpawnSessionState::FundingAutomaton;
            session.updated_at = now_ms;
        }
        record_session_audit(
            state,
            session_id,
            Some(SpawnSessionState::Spawning),
            SpawnSessionState::FundingAutomaton,
            SessionAuditActor::System,
            now_ms,
            "automaton initialized",
        );

        let net_forward_amount = {
            let session = state.sessions.get(session_id).expect("session exists");
            parse_amount(&session.net_forward_amount)?
        };
        runtime.funded_amount = amount_to_string(net_forward_amount);
        runtime.last_funded_at = Some(now_ms);

        let controller = complete_controller_handoff(&mut runtime, "factory")?;
        runtime.provider_keys_cleared = true;

        let registry_record = {
            let session = state.sessions.get_mut(session_id).expect("session exists");
            session.config.provider.open_router_api_key = None;
            session.config.provider.brave_search_api_key = None;
            session.state = SpawnSessionState::Complete;
            session.retryable = false;
            session.refundable = false;
            session.updated_at = now_ms;

            SpawnedAutomatonRecord {
                canister_id: runtime.canister_id.clone(),
                steward_address: session.steward_address.clone(),
                evm_address: runtime.evm_address.clone(),
                chain: session.chain.clone(),
                session_id: session.session_id.clone(),
                parent_id: session.parent_id.clone(),
                child_ids: session.child_ids.clone(),
                created_at: now_ms,
                version_commit,
            }
        };

        if let Some(parent_id) = registry_record.parent_id.as_ref() {
            if let Some(parent) = state.registry.get_mut(parent_id) {
                if parent
                    .child_ids
                    .iter()
                    .all(|child_id| child_id != &registry_record.canister_id)
                {
                    parent.child_ids.push(registry_record.canister_id.clone());
                }
            }
        }

        state
            .runtimes
            .insert(runtime.canister_id.clone(), runtime.clone());
        state
            .registry
            .insert(registry_record.canister_id.clone(), registry_record);
        record_session_audit(
            state,
            session_id,
            Some(SpawnSessionState::FundingAutomaton),
            SpawnSessionState::Complete,
            SessionAuditActor::System,
            now_ms,
            "spawn completed and controller handoff finalized",
        );

        Ok(SpawnExecutionReceipt {
            session_id: session_id.to_string(),
            automaton_canister_id: runtime.canister_id,
            automaton_evm_address: runtime.evm_address,
            funded_amount: amount_to_string(net_forward_amount),
            controller,
            completed_at: now_ms,
        })
    })
}

