  fastify.get("/api/automatons/:canisterId/monologue", async (request) => {
    const params = request.params as { canisterId: string };
    const query = request.query as {
      before?: string;
      limit?: string;
    };

    return fastify.indexerStore.listMonologue(params.canisterId, {
      before: normalizeCursor(query.before),
      limit: normalizeLimit(query.limit)
    });
  });
};

import { fileURLToPath } from "node:url";

export interface IndexerConfig {
  host: string;
  port: number;
  databasePath: string;
  websocketPath: string;
  seedCanisterIds: string[];
  icHost: string;
  fastPollIntervalMs: number;
  slowPollIntervalMs: number;
  pricePollIntervalMs: number;
}

export interface IndexerConfigOverrides {
  host?: string;
  port?: number;
  databasePath?: string;
  websocketPath?: string;
  seedCanisterIds?: string[];
  icHost?: string;
  fastPollIntervalMs?: number;
  slowPollIntervalMs?: number;
  pricePollIntervalMs?: number;
}

const DEFAULT_DATABASE_PATH = fileURLToPath(
  new URL("../data/indexer.sqlite", import.meta.url)
);

function parseNumber(value: string | undefined, fallback: number) {
  if (!value) {
    return fallback;
  }

  const parsed = Number(value);
  return Number.isFinite(parsed) && parsed > 0 ? parsed : fallback;
}

function parseSeedCanisterIds(value: string | undefined) {
  if (!value) {
    return [];
  }

  return value
    .split(",")
    .map((entry) => entry.trim())
    .filter((entry) => entry.length > 0);
}

export function resolveIndexerConfig(
  env: NodeJS.ProcessEnv = process.env,
  overrides: IndexerConfigOverrides = {}
): IndexerConfig {
  return {
    host: overrides.host ?? env.HOST ?? "0.0.0.0",
    port: overrides.port ?? parseNumber(env.PORT, 3001),
    databasePath: overrides.databasePath ?? env.INDEXER_DB_PATH ?? DEFAULT_DATABASE_PATH,
    websocketPath: overrides.websocketPath ?? env.INDEXER_WS_PATH ?? "/ws/events",
    seedCanisterIds:
      overrides.seedCanisterIds ?? parseSeedCanisterIds(env.INDEXER_SEED_CANISTER_IDS),
    icHost: overrides.icHost ?? env.INDEXER_IC_HOST ?? "https://ic0.app",
    fastPollIntervalMs:
      overrides.fastPollIntervalMs ?? parseNumber(env.INDEXER_FAST_POLL_INTERVAL_MS, 15_000),
    slowPollIntervalMs:
      overrides.slowPollIntervalMs ?? parseNumber(env.INDEXER_SLOW_POLL_INTERVAL_MS, 300_000),
    pricePollIntervalMs:
      overrides.pricePollIntervalMs ?? parseNumber(env.INDEXER_PRICE_POLL_INTERVAL_MS, 60_000)
  };
}

    const summary = detailToSummary(detail);
    const now = Date.now();
    const summaryJson = sqlString(JSON.stringify(summary));
    const detailJson = sqlString(JSON.stringify(detail));

    await this.runSql(`
      INSERT INTO automatons (
        canister_id,
        steward_address,
        chain,
        tier,
        last_transition_at,
        created_at,
        updated_at,
        summary_json,
        detail_json
      ) VALUES (
        ${sqlString(detail.canisterId)},
        ${sqlString(detail.steward.address)},
        ${sqlString(detail.chain)},
        ${sqlString(detail.tier)},
        ${sqlNumber(detail.runtime.lastTransitionAt)},
        ${sqlNumber(detail.createdAt)},
        ${sqlNumber(now)},
        ${summaryJson},
        ${detailJson}
      )
      ON CONFLICT(canister_id) DO UPDATE SET
        steward_address = excluded.steward_address,
        chain = excluded.chain,
        tier = excluded.tier,
        last_transition_at = excluded.last_transition_at,
        updated_at = excluded.updated_at,
        summary_json = excluded.summary_json,
        detail_json = excluded.detail_json;
    `);
  }

  async listMonologue(canisterId: string, query: MonologueQuery): Promise<MonologuePage> {
    await this.initialize();

    const clauses = [`canister_id = ${sqlString(canisterId)}`];
    if (query.before !== undefined) {
      clauses.push(`timestamp < ${sqlNumber(query.before)}`);
    }

    const rows = await this.queryJson<{ entry_json: string; timestamp: number }>(
      `SELECT entry_json, timestamp
       FROM monologue
       WHERE ${clauses.join(" AND ")}
       ORDER BY timestamp DESC, turn_id DESC
       LIMIT ${sqlNumber(query.limit + 1)};`
    );

    const hasMore = rows.length > query.limit;
    const entries = rows.slice(0, query.limit).map((row) => {
      return JSON.parse(String(row.entry_json)) as MonologueEntry;
    });
    const lastEntry = entries.at(-1);

    return {
      entries,
      hasMore,
      nextCursor: hasMore && lastEntry ? lastEntry.timestamp : null
    };
  }

  async appendMonologue(canisterId: string, entries: MonologueEntry[]) {
    await this.initialize();

    if (entries.length === 0) {
      return;
    }

    const statements = entries.map((entry) => {
      return `
        INSERT INTO monologue (canister_id, timestamp, turn_id, entry_json)
        VALUES (
          ${sqlString(canisterId)},
          ${sqlNumber(entry.timestamp)},
          ${sqlString(entry.turnId)},
          ${sqlString(JSON.stringify(entry))}
        )
        ON CONFLICT(canister_id, timestamp, turn_id) DO UPDATE SET
          entry_json = excluded.entry_json
      `;
    });

    await this.runSql(statements.join(";\n"));
  }

  async setPrice(symbol: string, value: number | null) {
    await this.initialize();

    await this.runSql(`
      INSERT INTO prices (symbol, value, updated_at)
      VALUES (
        ${sqlString(symbol)},
        ${sqlNullableNumber(value)},
        ${sqlNumber(Date.now())}
      )
      ON CONFLICT(symbol) DO UPDATE SET
        value = excluded.value,
        updated_at = excluded.updated_at;
    `);
  }

  private async getPrice(symbol: string) {
    const [row] = await this.queryJson<{ value: number | null }>(
      `SELECT value
       FROM prices
       WHERE symbol = ${sqlString(symbol)}
       LIMIT 1;`
    );

    return row?.value === null || row?.value === undefined ? null : Number(row.value);
  }

  private async runSql(sql: string) {
    await execFileAsync(this.sqliteBin, [this.databasePath, sql], {
      maxBuffer: 1024 * 1024
    });
  }

  private async queryJson<Row extends SqliteJsonRow>(sql: string) {
    const { stdout } = await execFileAsync(this.sqliteBin, ["-json", this.databasePath, sql], {
      maxBuffer: 1024 * 1024
    });

    if (stdout.trim().length === 0) {
      return [] as Row[];
    }

    return JSON.parse(stdout) as Row[];
  }
}

export function createSqliteStore(options: SqliteStoreOptions): IndexerStore {
  return new SqliteCliStore(options);
}

