function sqlString(value: string) {
  return `'${value.replaceAll("'", "''")}'`;
}

function sqlNumber(value: number) {
  if (!Number.isFinite(value)) {
    throw new TypeError(`Expected finite number, received ${value}`);
  }

  return String(value);
}

function sqlNullableNumber(value: number | null) {
  return value === null ? "NULL" : sqlNumber(value);
}

function detailToSummary(detail: AutomatonDetail): AutomatonSummary {
  return {
    canisterId: detail.canisterId,
    ethAddress: detail.ethAddress,
    chain: detail.chain,
    chainId: detail.chainId,
    name: detail.name,
    tier: detail.tier,
    agentState: detail.runtime.agentState,
    ethBalanceWei: detail.financials.ethBalanceWei,
    usdcBalanceRaw: detail.financials.usdcBalanceRaw,
    cyclesBalance: detail.financials.cyclesBalance,
    netWorthEth: detail.financials.netWorthEth,
    netWorthUsd: detail.financials.netWorthUsd,
    heartbeatIntervalSeconds: detail.runtime.heartbeatIntervalSeconds,
    steward: detail.steward,
    gridPosition: detail.gridPosition,
    corePatternIndex: detail.corePatternIndex,
    corePattern: detail.corePattern,
    parentId: detail.parentId,
    createdAt: detail.createdAt,
    lastTransitionAt: detail.runtime.lastTransitionAt
  };
}

async function loadSchemaSql() {
  const candidates = [
    new URL("./schema.sql", import.meta.url),
    new URL("../../src/store/schema.sql", import.meta.url)
  ];

  for (const candidate of candidates) {
    try {
      await access(candidate);
      return await readFile(candidate, "utf8");
    } catch {
      continue;
    }
  }

  throw new Error("Unable to locate SQLite schema.sql");
}

class SqliteCliStore implements IndexerStore {
  readonly databasePath: string;
  readonly sqliteBin: string;

  private initialized = false;
  private readonly schemaSqlPromise: Promise<string>;

  constructor(options: SqliteStoreOptions) {
    this.databasePath = options.databasePath;
    this.sqliteBin = options.sqliteBin ?? "sqlite3";
    this.schemaSqlPromise = loadSchemaSql();
  }

  async initialize() {
    if (this.initialized) {
      return;
    }

    await mkdir(dirname(this.databasePath), { recursive: true });
    await this.runSql(await this.schemaSqlPromise);
    this.initialized = true;
  }

  async close() {
    this.initialized = false;
  }

  async getHealth(): Promise<StoreHealth> {
    await this.initialize();

    const [automatonCountRow] = await this.queryJson<{ count: number }>(
      "SELECT COUNT(*) AS count FROM automatons;"
    );
    const [monologueCountRow] = await this.queryJson<{ count: number }>(
      "SELECT COUNT(*) AS count FROM monologue;"
    );

    return {
      ok: true,
      driver: "sqlite3-cli",
      databasePath: this.databasePath,
      counts: {
        automatons: Number(automatonCountRow?.count ?? 0),
        monologueEntries: Number(monologueCountRow?.count ?? 0)
      }
    };
  }

  async listAutomatons(filters: AutomatonFilters = {}): Promise<AutomatonListResponse> {
    await this.initialize();

    const where: string[] = [];
    if (filters.steward) {
      where.push(`steward_address = ${sqlString(filters.steward)}`);
    }
    if (filters.chain) {
      where.push(`chain = ${sqlString(filters.chain)}`);
    }
    if (filters.tier) {
      where.push(`tier = ${sqlString(filters.tier)}`);
    }

    const whereClause = where.length > 0 ? `WHERE ${where.join(" AND ")}` : "";
    const summaryRows = await this.queryJson<{ summary_json: string }>(
      `SELECT summary_json
       FROM automatons
       ${whereClause}
       ORDER BY last_transition_at DESC, canister_id ASC;`
    );
    const summaries = summaryRows.map((row) => {
      return JSON.parse(String(row.summary_json)) as AutomatonSummary;
    });
    const price = await this.getPrice("ethUsd");

    return {
      automatons: summaries,
      total: summaries.length,
      prices: {
        ethUsd: price
      }
    };
  }

  async getAutomatonDetail(canisterId: string) {
    await this.initialize();

    const [row] = await this.queryJson<{ detail_json: string }>(
      `SELECT detail_json
       FROM automatons
       WHERE canister_id = ${sqlString(canisterId)}
       LIMIT 1;`
    );

    if (!row) {
      return null;
    }

    return JSON.parse(String(row.detail_json)) as AutomatonDetail;
  }

  async upsertAutomaton(detail: AutomatonDetail) {
    await this.initialize();

    const summary = detailToSummary(detail);
    const now = Date.now();
    const summaryJson = sqlString(JSON.stringify(summary));
    const detailJson = sqlString(JSON.stringify(detail));

    await this.runSql(`
      INSERT INTO automatons (
        canister_id,
        steward_address,
        chain,
        tier,
        last_transition_at,
        created_at,
        updated_at,
        summary_json,
        detail_json
      ) VALUES (
        ${sqlString(detail.canisterId)},
        ${sqlString(detail.steward.address)},
        ${sqlString(detail.chain)},
        ${sqlString(detail.tier)},
        ${sqlNumber(detail.runtime.lastTransitionAt)},
        ${sqlNumber(detail.createdAt)},
        ${sqlNumber(now)},
        ${summaryJson},
        ${detailJson}
      )
      ON CONFLICT(canister_id) DO UPDATE SET
        steward_address = excluded.steward_address,
        chain = excluded.chain,
        tier = excluded.tier,
        last_transition_at = excluded.last_transition_at,
        updated_at = excluded.updated_at,
        summary_json = excluded.summary_json,
        detail_json = excluded.detail_json;
    `);
  }

  async listMonologue(canisterId: string, query: MonologueQuery): Promise<MonologuePage> {
    await this.initialize();

    const clauses = [`canister_id = ${sqlString(canisterId)}`];
    if (query.before !== undefined) {
      clauses.push(`timestamp < ${sqlNumber(query.before)}`);
    }

    const rows = await this.queryJson<{ entry_json: string; timestamp: number }>(
      `SELECT entry_json, timestamp
       FROM monologue
       WHERE ${clauses.join(" AND ")}
       ORDER BY timestamp DESC, turn_id DESC
       LIMIT ${sqlNumber(query.limit + 1)};`
    );

    const hasMore = rows.length > query.limit;
    const entries = rows.slice(0, query.limit).map((row) => {
      return JSON.parse(String(row.entry_json)) as MonologueEntry;
    });
    const lastEntry = entries.at(-1);

    return {
      entries,
      hasMore,
      nextCursor: hasMore && lastEntry ? lastEntry.timestamp : null
    };
  }

  async appendMonologue(canisterId: string, entries: MonologueEntry[]) {
    await this.initialize();

    if (entries.length === 0) {
      return;
    }

    const statements = entries.map((entry) => {
      return `
        INSERT INTO monologue (canister_id, timestamp, turn_id, entry_json)
        VALUES (
          ${sqlString(canisterId)},
          ${sqlNumber(entry.timestamp)},
          ${sqlString(entry.turnId)},
          ${sqlString(JSON.stringify(entry))}
        )
        ON CONFLICT(canister_id, timestamp, turn_id) DO UPDATE SET
          entry_json = excluded.entry_json
      `;
    });

    await this.runSql(statements.join(";\n"));
  }

  async setPrice(symbol: string, value: number | null) {
    await this.initialize();

    await this.runSql(`
      INSERT INTO prices (symbol, value, updated_at)
      VALUES (
        ${sqlString(symbol)},
        ${sqlNullableNumber(value)},
        ${sqlNumber(Date.now())}
      )
      ON CONFLICT(symbol) DO UPDATE SET
        value = excluded.value,
        updated_at = excluded.updated_at;
    `);
  }

  private async getPrice(symbol: string) {
    const [row] = await this.queryJson<{ value: number | null }>(
      `SELECT value
       FROM prices
       WHERE symbol = ${sqlString(symbol)}
       LIMIT 1;`
    );

    return row?.value === null || row?.value === undefined ? null : Number(row.value);
  }

  private async runSql(sql: string) {
    await execFileAsync(this.sqliteBin, [this.databasePath, sql], {
      maxBuffer: 1024 * 1024
    });
  }

  private async queryJson<Row extends SqliteJsonRow>(sql: string) {
    const { stdout } = await execFileAsync(this.sqliteBin, ["-json", this.databasePath, sql], {
      maxBuffer: 1024 * 1024
    });

    if (stdout.trim().length === 0) {
      return [] as Row[];
    }

    return JSON.parse(stdout) as Row[];
  }
}

export function createSqliteStore(options: SqliteStoreOptions): IndexerStore {
  return new SqliteCliStore(options);
}

