import { createHash } from "node:crypto";
import type { IncomingMessage, Server } from "node:http";
import type { Socket } from "node:net";

import {
  AUTOMATON_EVENT_TYPES,
  SPAWN_EVENT_TYPES,
  type RealtimeEvent
} from "@ic-automaton/shared";

const WEBSOCKET_GUID = "258EAFA5-E914-47DA-95CA-C5AB0DC85B11";

interface RealtimeClient {
  canisterId?: string;
  socket: Socket;
}

export interface RealtimeSnapshot {
  websocketPath: string;
  clientCount: number;
  supportedEventTypes: string[];
}

function encodeTextFrame(payload: string) {
  const message = Buffer.from(payload);

  if (message.length < 126) {
    return Buffer.concat([Buffer.from([0x81, message.length]), message]);
  }

  if (message.length < 65_536) {
    const header = Buffer.alloc(4);
    header[0] = 0x81;
    header[1] = 126;
    header.writeUInt16BE(message.length, 2);
    return Buffer.concat([header, message]);
  }

  const header = Buffer.alloc(10);
  header[0] = 0x81;
  header[1] = 127;
  header.writeBigUInt64BE(BigInt(message.length), 2);
  return Buffer.concat([header, message]);
}

function extractEventCanisterIds(event: RealtimeEvent) {
  switch (event.type) {
    case "spawn":
      return [event.automaton.canisterId];
    case "update":
    case "action":
    case "monologue":
    case "offline":
      return [event.canisterId];
    case "message":
      return [event.fromCanisterId, event.toCanisterId];
    default:
      return [];
  }
}

export function shouldDeliverEvent(canisterId: string | undefined, event: RealtimeEvent) {
  if (!canisterId) {
    return true;
  }

  return extractEventCanisterIds(event).includes(canisterId);
}

export class RealtimeHub {
  private readonly clients = new Set<RealtimeClient>();
  private server?: Server;
  private readonly handleUpgradeBound: (
    request: IncomingMessage,
    socket: Socket,
    head: Buffer
  ) => void;

  constructor(readonly websocketPath = "/ws/events") {
    this.handleUpgradeBound = this.handleUpgrade.bind(this);
  }

  attach(server: Server) {
    if (this.server === server) {
      return;
    }

    if (this.server) {
      this.server.off("upgrade", this.handleUpgradeBound);
    }

    this.server = server;
    this.server.on("upgrade", this.handleUpgradeBound);
  }

  async close() {
    if (this.server) {
      this.server.off("upgrade", this.handleUpgradeBound);
      this.server = undefined;
    }

    for (const client of this.clients) {
      client.socket.end();
      client.socket.destroy();
    }

    this.clients.clear();
  }

  broadcast(event: RealtimeEvent) {
    const frame = encodeTextFrame(JSON.stringify(event));

    for (const client of this.clients) {
      if (client.socket.destroyed) {
        this.clients.delete(client);
        continue;
      }

      if (!shouldDeliverEvent(client.canisterId, event)) {
        continue;
      }

      client.socket.write(frame);
    }
  }

  getSnapshot(): RealtimeSnapshot {
    return {
      websocketPath: this.websocketPath,
      clientCount: this.clients.size,
      supportedEventTypes: [
        ...AUTOMATON_EVENT_TYPES,
        ...SPAWN_EVENT_TYPES
      ]
    };
  }

  private handleUpgrade(request: IncomingMessage, socket: Socket, head: Buffer) {
    const requestUrl = new URL(request.url ?? this.websocketPath, "http://127.0.0.1");
    if (requestUrl.pathname !== this.websocketPath) {
      return;
    }

    const key = request.headers["sec-websocket-key"];
    const upgrade = request.headers.upgrade;

    if (typeof key !== "string" || upgrade?.toLowerCase() !== "websocket") {
      socket.write("HTTP/1.1 400 Bad Request\r\n\r\n");
      socket.destroy();
      return;
    }

    const accept = createHash("sha1")
      .update(`${key}${WEBSOCKET_GUID}`)
      .digest("base64");

    socket.write(
      [
        "HTTP/1.1 101 Switching Protocols",
        "Upgrade: websocket",
        "Connection: Upgrade",
        `Sec-WebSocket-Accept: ${accept}`,
        "\r\n"
      ].join("\r\n")
    );

    if (head.length > 0) {
      socket.unshift(head);
    }

    socket.setNoDelay(true);

    const client: RealtimeClient = {
      socket,
      canisterId: requestUrl.searchParams.get("canisterId") ?? undefined
    };

    this.clients.add(client);

    const cleanup = () => {
      this.clients.delete(client);
    };

    socket.on("close", cleanup);
    socket.on("end", cleanup);
    socket.on("error", cleanup);
  }
}

import websocket from "@fastify/websocket";
import Fastify, { type FastifyBaseLogger, type FastifyInstance } from "fastify";
import { fileURLToPath } from "node:url";

import { resolveIndexerConfig, type IndexerConfigOverrides } from "./config.js";
import { automatonRoutes } from "./routes/automatons.js";
import { healthRoutes } from "./routes/health.js";
import { realtimeRoutes } from "./routes/realtime.js";
import { createSqliteStore, type IndexerStore } from "./store/sqlite.js";
import "./types.js";
import { RealtimeHub } from "./ws/events.js";

export interface BuildServerOptions {
  config?: IndexerConfigOverrides;
  logger?: boolean | FastifyBaseLogger;
  store?: IndexerStore;
  realtimeHub?: RealtimeHub;
}

export function buildServer(options: BuildServerOptions = {}): FastifyInstance {
  const config = resolveIndexerConfig(process.env, options.config);
  const store =
    options.store ??
    createSqliteStore({
      databasePath: config.databasePath
    });
  const realtimeHub = options.realtimeHub ?? new RealtimeHub(config.websocketPath);

  const app = Fastify({
    logger: options.logger ?? false
  });

  app.decorate("startedAt", Date.now());
  app.decorate("indexerConfig", config);
  app.decorate("indexerStore", store);
  app.decorate("realtimeHub", realtimeHub);

  app.register(websocket);

  app.addHook("onReady", async () => {
    await app.indexerStore.initialize();
  });

  app.addHook("onClose", async () => {
    await Promise.all([
      app.realtimeHub.close(),
      app.indexerStore.close()
    ]);
  });

  app.register(healthRoutes);
  app.register(automatonRoutes);
  app.register(realtimeRoutes);

  return app;
}

async function start() {
  const app = buildServer();

  try {
    await app.listen({
      host: app.indexerConfig.host,
      port: app.indexerConfig.port
    });
  } catch (error) {
    app.log.error(error);
    process.exitCode = 1;
  }
}

if (process.argv[1] && fileURLToPath(import.meta.url) === process.argv[1]) {
  void start();
}

import type { FastifyPluginAsync } from "fastify";

export const realtimeRoutes: FastifyPluginAsync = async (fastify) => {
  fastify.route({
    method: "GET",
    url: fastify.indexerConfig.websocketPath,
    handler: async (_request, reply) => {
      reply.code(426);
      reply.header("connection", "Upgrade");
      reply.header("upgrade", "websocket");

      return {
        ok: false,
        error: "Upgrade Required",
        realtime: fastify.realtimeHub.getSnapshot()
      };
    },
    wsHandler: (socket, request) => {
      const query = request.query as { canisterId?: string };
      const canisterId =
        typeof query.canisterId === "string" && query.canisterId.trim().length > 0
          ? query.canisterId.trim()
          : undefined;

      fastify.realtimeHub.connect(socket, canisterId);
    }
  });
};

